import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Share2, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2 } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, api } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    queue,
    setQueue,
    likedSongs,
    toggleLike,
    isShuffling
  } = usePlayerStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  // Swipe State
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  // Check if current song is liked
  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  // Extract Dominant Color
  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);

        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#2a2a2a'); 
      }
    };

    img.onerror = () => setDominantColor('#2a2a2a');

  }, [currentSong]);

  // Handle Song Changes and Playback
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !currentSong) return;

    const playAudio = async () => {
      try {
        if (isPlaying) {
          await audio.play();
        } else {
          audio.pause();
        }
      } catch (error) {
         // Autoplay policy or interruption
         if (isPlaying) setIsPlaying(false);
      }
    };

    playAudio();
  }, [currentSong, isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleEnded = async () => {
    if (currentSong && queue.findIndex(s => s.id === currentSong.id) === queue.length - 1) {
       try {
         const artist = currentSong.artists?.primary?.[0]?.name || "";
         const query = `${artist} ${currentSong.language} songs`; 
         const similarSongs = await api.searchSongs(query);
         const newSongs = similarSongs.filter(s => !queue.some(q => q.id === s.id)).slice(0, 5);

         if (newSongs.length > 0) {
            setQueue([...queue, ...newSongs]);
         }
       } catch (e) {
         console.error("Auto-queue failed", e);
       } finally {
         nextSong();
       }
    } else {
      nextSong();
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
    }
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = (e: React.TouchEvent | React.MouseEvent | any) => {
      setIsDragging(false);
       // Ensure final value is set
       if (audioRef.current) {
         audioRef.current.currentTime = progress;
       }
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Swipe Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;

    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;

    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    // Horizontal Swipe (Next/Prev)
    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Vertical Swipe (Down -> Close)
    if (diffY < -100 && Math.abs(diffY) > Math.abs(diffX)) {
        setFullScreen(false);
    }

    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const audioSrc = getAudioUrl(currentSong.downloadUrl);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";
  const featuredArtistName = currentSong.artists?.featured?.[0]?.name;

  return (
    <>
        <audio 
            ref={audioRef}
            src={audioSrc}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={handleEnded}
            onWaiting={() => setIsBuffering(true)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence>
        {isFullScreen && (
        <motion.div 
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed inset-0 z-[200] flex flex-col bg-[#0a0a0a] overflow-hidden"
            onTouchStart={handleTouchStart}
            onTouchEnd={handleTouchEnd}
        >
            {/* Dynamic Background */}
            <div className="absolute inset-0 z-0 overflow-hidden">
                <div 
                    className="absolute inset-0 transition-colors duration-1000 ease-in-out opacity-60"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #050505)` }}
                />
                 {/* Mesh Gradient Effect */}
                <div className="absolute -top-[50%] -left-[50%] w-[200%] h-[200%] opacity-30 animate-spin-slow mix-blend-overlay"
                     style={{ background: `conic-gradient(from 0deg, transparent, ${dominantColor}, transparent)` }}>
                </div>
                <div className="absolute inset-0 bg-black/20 backdrop-blur-[100px]"></div>
                {/* Noise Texture */}
                <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 200 200\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.8\' numOctaves=\'3\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E")'}}></div>
            </div>

            {/* Main Content */}
            <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-4 md:px-12 md:pb-12">

                {/* Header */}
                <div className="flex items-center justify-between shrink-0 h-16">
                    <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full transition-colors active:scale-90">
                        <ChevronDown size={28} className="text-white" />
                    </button>
                    <div className="flex flex-col items-center opacity-0 md:opacity-100 transition-opacity">
                        <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">Playing From</span>
                        <span className="text-xs font-bold text-white">Artist Radio</span>
                    </div>
                    <button className="p-2 -mr-2 hover:bg-white/10 rounded-full transition-colors active:scale-90">
                        <MoreHorizontal size={24} className="text-white" />
                    </button>
                </div>

                {/* Album Art Section */}
                <div className="flex-1 flex items-center justify-center py-6 min-h-0">
                     <div className="relative w-full max-w-[350px] aspect-square group">
                        {/* Colored Glow Shadow */}
                        <div 
                            className="absolute inset-4 rounded-full blur-[40px] opacity-40 transition-colors duration-1000"
                            style={{ backgroundColor: dominantColor }}
                        ></div>
                        <img 
                            src={imageUrl} 
                            alt={currentSong.name} 
                            className="relative w-full h-full object-cover rounded-2xl shadow-2xl transition-transform duration-500 ease-out" 
                        />
                     </div>
                </div>

                {/* Track Info & Controls */}
                <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">

                    {/* Metadata */}
                    <div className="flex items-center justify-between">
                        <div className="flex flex-col overflow-hidden mr-6 flex-1">
                            <div className="h-8 md:h-10 relative overflow-hidden w-full">
                                {/* Marquee Effect for Long Titles */}
                                <h1 className={`text-2xl md:text-3xl font-bold text-white whitespace-nowrap ${currentSong.name.length > 20 ? 'animate-marquee pl-[100%]' : ''}`}>
                                    {currentSong.name}
                                </h1>
                            </div>
                            <p className="text-white/60 text-lg md:text-xl truncate font-medium -mt-1">
                                {primaryArtistName}
                            </p>
                        </div>
                        <button onClick={() => toggleLike(currentSong)} className="transition-all active:scale-75 hover:scale-110 shrink-0">
                            {isLiked ? (
                                <CheckCircle2 size={32} className="text-[#1DB954] fill-[#1DB954] text-black" />
                            ) : (
                                <PlusCircle size={32} className="text-white/60 hover:text-white" />
                            )}
                        </button>
                    </div>

                    {/* Custom Scrubber */}
                    <div className="group flex flex-col gap-2 pt-2">
                        <div className="relative h-1 w-full bg-white/20 rounded-full touch-none group-hover:h-1.5 transition-all duration-300">
                             {/* Fill */}
                             <div 
                                className="absolute left-0 top-0 bottom-0 bg-white rounded-full transition-all duration-100 ease-linear"
                                style={{ width: `${(progress / (duration || 1)) * 100}%` }}
                             >
                                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity scale-0 group-hover:scale-100"></div>
                             </div>
                             {/* Input for interaction */}
                             <input 
                                type="range" 
                                min="0" 
                                max={duration || 100} 
                                value={progress}
                                onChange={handleSeek}
                                onTouchStart={handleSeekStart}
                                onTouchEnd={handleSeekEnd}
                                onMouseDown={handleSeekStart}
                                onMouseUp={handleSeekEnd}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                            />
                        </div>
                        <div className="flex justify-between text-[11px] text-white/40 font-bold tracking-wide font-mono">
                            <span>{formatTime(progress)}</span>
                            <span>{formatTime(duration)}</span>
                        </div>
                    </div>

                    {/* Main Controls */}
                    <div className="flex items-center justify-between -mx-2">
                        <button className={`p-2 transition-colors hover:text-white ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}>
                            <Shuffle size={20} />
                        </button>

                        <div className="flex items-center gap-6 md:gap-10">
                            <button onClick={prevSong} className="text-white hover:text-white/70 transition-transform active:scale-75">
                                <SkipBack size={36} fill="currentColor" />
                            </button>

                            <button 
                                onClick={togglePlay}
                                className="bg-white text-black rounded-full w-16 h-16 md:w-20 md:h-20 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-[0_0_24px_rgba(255,255,255,0.2)]"
                            >
                                {isBuffering ? (
                                    <Loader2 size={32} className="animate-spin" />
                                ) : isPlaying ? (
                                    <Pause size={32} fill="currentColor" />
                                ) : (
                                    <Play size={32} fill="currentColor" className="ml-1" />
                                )}
                            </button>

                            <button onClick={nextSong} className="text-white hover:text-white/70 transition-transform active:scale-75">
                                <SkipForward size={36} fill="currentColor" />
                            </button>
                        </div>

                        <button className="p-2 text-white/40 hover:text-white transition-colors">
                            <Repeat size={20} />
                        </button>
                    </div>
                </div>

                {/* Bottom Actions */}
                <div className="flex items-center justify-between px-2 md:px-6">
                    <button className="text-white/50 hover:text-white transition-colors active:scale-90"><Share2 size={20} /></button>
                    <div className="flex items-center gap-6">
                        <button className="text-white/50 hover:text-white transition-colors active:scale-90"><Mic2 size={20} /></button>
                        <button className="text-white/50 hover:text-white transition-colors active:scale-90"><ListMusic size={22} /></button>
                    </div>
                </div>
            </div>
        </motion.div>
        )}
        </AnimatePresence>

        {/* --- MINI PLAYER (Premium Floating Bar) --- */}
        <AnimatePresence>
        {!isFullScreen && (
            <motion.div 
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: 20, opacity: 0 }}
                onClick={() => setFullScreen(true)}
                // Positioned above bottom nav on mobile (approx 85px), bottom of screen on desktop
                className="fixed bottom-[90px] md:bottom-4 left-3 right-3 md:left-[50%] md:right-auto md:translate-x-[-50%] md:w-[420px] h-[60px] bg-[#1a1a1a]/90 backdrop-blur-xl border border-white/5 rounded-[14px] flex items-center pr-4 shadow-[0_8px_24px_rgba(0,0,0,0.5)] z-[150] cursor-pointer overflow-hidden group hover:bg-[#202020]/90 transition-colors"
            >
                {/* Artwork */}
                <div className="relative h-12 w-12 rounded-lg overflow-hidden ml-2 mr-3 shrink-0 shadow-sm">
                   <img src={imageUrl} alt="cover" className="h-full w-full object-cover" />
                </div>

                {/* Text */}
                <div className="flex-1 min-w-0 flex flex-col justify-center mr-2">
                    <div className="flex items-center gap-2">
                        <span className={`text-white font-bold text-xs md:text-sm truncate ${isPlaying ? 'text-[#1DB954]' : ''}`}>{currentSong.name}</span>
                        <span className="text-white/40 text-[10px] hidden sm:inline">•</span>
                        <span className="text-white/60 text-xs truncate hidden sm:inline">{primaryArtistName}</span>
                    </div>
                    <span className="text-white/60 text-xs truncate sm:hidden">{primaryArtistName}</span>
                </div>

                {/* Controls */}
                <div className="flex items-center gap-3">
                     <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="text-white/40 hover:text-[#1DB954] transition-colors active:scale-90 hidden sm:block">
                        <Heart size={20} fill={isLiked ? "#1DB954" : "transparent"} className={isLiked ? "text-[#1DB954]" : ""} />
                     </button>
                     <button 
                        onClick={(e) => { e.stopPropagation(); togglePlay(); }} 
                        className="text-black bg-white h-9 w-9 rounded-full flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-lg"
                    >
                        {isBuffering ? (
                            <Loader2 size={16} className="animate-spin" />
                        ) : isPlaying ? (
                            <Pause size={16} fill="currentColor" />
                        ) : (
                            <Play size={16} fill="currentColor" className="ml-0.5" />
                        )}
                     </button>
                </div>

                 {/* Premium Progress Bar (Bottom Line) */}
                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/10">
                     <div 
                        className="h-full bg-white/90 rounded-r-full shadow-[0_0_10px_rgba(255,255,255,0.5)] transition-all duration-200" 
                        style={{ width: `${(progress / (duration || 1)) * 100}%` }}
                    ></div>
                </div>
            </motion.div>
        )}
        </AnimatePresence>
    </>
  );
};

import React from 'react';
import { Play } from 'lucide-react';
import { SearchResult } from '../types';
import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';

interface SongCardProps {
  item: SearchResult;
  onPlay?: () => void;
  subtitle?: string;
  round?: boolean;
}

export const SongCard: React.FC<SongCardProps> = ({ item, onPlay, subtitle, round = false }) => {
  const navigate = useNavigate();
  const imageUrl = getImageUrl(item.image);

  const handleClick = () => {
    if (item.type === 'album') {
      navigate(`/album/${item.id}`);
    } else if (item.type === 'artist') {
      navigate(`/artist/${item.id}`, { state: { artist: item } });
    } else if (item.type === 'song' && onPlay) {
      onPlay();
    }
  };

  const handlePlayClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onPlay) onPlay();
  };

  // Safe subtitle generation
  let safeSubtitle = subtitle;
  if (!safeSubtitle) {
      if (item.type === 'song') {
          safeSubtitle = item.artists?.primary?.[0]?.name || item.artists?.all?.[0]?.name || 'Artist';
      } else if (item.type === 'album') {
          safeSubtitle = `Album • ${item.artists?.primary?.[0]?.name || 'Artist'}`;
      } else if (item.type === 'artist') {
          safeSubtitle = 'Artist';
      } else if (item.type === 'playlist') {
          safeSubtitle = item.subtitle || 'Playlist';
      }
  }

  // Handle display title (Playlist has 'title', others have 'name')
  const displayTitle = item.type === 'playlist' ? item.title : item.name;

  return (
    <div 
      onClick={handleClick}
      className="group relative bg-[#181818]/60 backdrop-blur-sm hover:bg-[#282828] p-3 rounded-xl transition-all duration-300 cursor-pointer w-[160px] md:w-[180px] shrink-0 border border-white/5 hover:border-white/10 hover:-translate-y-1"
    >
      <div className={`relative w-full aspect-square mb-3 shadow-lg ${round ? 'rounded-full' : 'rounded-lg'} overflow-hidden`}>
        <img 
          src={imageUrl} 
          alt={displayTitle} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
          loading="lazy"
        />
        {/* Play Button Overlay */}
        {!round && item.type !== 'artist' && (
          <button 
            onClick={handlePlayClick}
            className="absolute bottom-2 right-2 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300 bg-[#1DB954] text-black rounded-full p-3 shadow-xl flex items-center justify-center hover:scale-110 active:scale-95 z-20"
          >
            <Play size={20} fill="black" className="ml-1" />
          </button>
        )}
      </div>
      <div className="flex flex-col gap-0.5 min-h-[48px]">
        <h3 className="text-white font-bold truncate text-[15px] mb-1 leading-tight group-hover:underline decoration-1 underline-offset-2">
          {displayTitle}
        </h3>
        <p className="text-[#A7A7A7] text-[13px] truncate font-medium">
          {safeSubtitle}
        </p>
      </div>
    </div>
  );
};

import React from 'react';
import { usePlayerStore } from '../store/playerStore';
import { ArrowLeft, Play, Pause, Clock3, Heart, Download, ListFilter } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { getImageUrl } from '../services/api';
import { motion } from 'framer-motion';

export const LikedSongs: React.FC = () => {
  const { likedSongs, playSong, currentSong, isPlaying, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  const handlePlayAll = () => {
    if (likedSongs.length > 0) {
      playSong(likedSongs[0], likedSongs);
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: {
        staggerChildren: 0.05
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0 }
  };

  return (
    <div className="min-h-full pb-32 relative isolate">
      {/* Deep Atmosphere Background */}
      <div className="fixed inset-0 bg-[#121212] -z-20"></div>
      <div className="absolute top-0 left-0 right-0 h-[500px] bg-gradient-to-b from-[#5038a0] via-[#2d2060] to-[#121212] -z-10 opacity-80" />

      {/* Sticky Header */}
      <div className="sticky top-0 z-30 px-6 py-4 flex items-center gap-4 bg-[#121212]/0 backdrop-blur-md transition-colors duration-300">
          <button 
            onClick={() => navigate(-1)} 
            className="w-8 h-8 rounded-full bg-black/20 hover:bg-black/40 flex items-center justify-center text-white transition-colors"
          >
             <ArrowLeft size={20} />
          </button>
          <span className="font-bold text-lg text-white opacity-0 md:opacity-100 transition-opacity">Liked Songs</span>
      </div>

      <div className="px-6 md:px-10">
        {/* Hero Section */}
        <div className="flex flex-col md:flex-row items-end gap-6 mb-8 pt-2">
            <motion.div 
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ duration: 0.5 }}
                className="w-[160px] h-[160px] md:w-[240px] md:h-[240px] bg-gradient-to-br from-[#450af5] to-[#8e8ee5] flex items-center justify-center shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-lg shrink-0 group relative overflow-hidden"
            >
                <Heart size={80} fill="white" className="text-white drop-shadow-xl group-hover:scale-110 transition-transform duration-500" />
                <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            </motion.div>

            <div className="flex flex-col gap-1 md:gap-3 mb-2 flex-1">
                <span className="text-xs md:text-sm font-bold uppercase tracking-wider text-white hidden md:block">Playlist</span>
                <h1 className="text-4xl md:text-7xl lg:text-8xl font-black text-white tracking-tighter leading-none drop-shadow-lg">Liked Songs</h1>
                <div className="flex items-center flex-wrap gap-2 text-sm text-white/90 font-medium mt-2">
                    <div className="w-6 h-6 rounded-full bg-gradient-to-tr from-orange-400 to-red-500 flex items-center justify-center text-white text-[10px] font-bold shadow-md">Y</div>
                    <span className="hover:underline cursor-pointer font-bold">You</span>
                    <span className="hidden md:inline">•</span>
                    <span className="w-1 h-1 rounded-full bg-white/50 md:hidden"></span>
                    <span>{likedSongs.length} songs</span>
                </div>
            </div>
        </div>

        {/* Action Bar */}
        <div className="flex items-center justify-between mb-8">
             <div className="flex items-center gap-6">
                 <button 
                    onClick={handlePlayAll}
                    className="w-14 h-14 rounded-full bg-[#1DB954] flex items-center justify-center shadow-[0_8px_24px_rgba(29,185,84,0.3)] hover:scale-105 active:scale-95 transition-all group hover:bg-[#1ed760]"
                 >
                    {isPlaying && likedSongs.some(s => s.id === currentSong?.id) ? (
                        <Pause size={28} fill="black" className="text-black" />
                    ) : (
                        <Play size={28} fill="black" className="text-black ml-1 group-hover:scale-110 transition-transform" />
                    )}
                 </button>
                 <button className="text-white/60 hover:text-white transition-colors p-2 rounded-full hover:bg-white/5">
                    <Download size={24} />
                 </button>
             </div>
             <div className="flex items-center gap-4 text-white/60">
                 <button className="hover:text-white transition-colors p-2"><Search size={22} /></button>
                 <button className="hover:text-white transition-colors p-2"><ListFilter size={22} /></button>
             </div>
