import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Share2, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2 } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, api } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    queue,
    setQueue,
    likedSongs,
    toggleLike,
    isShuffling
  } = usePlayerStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [blobUrl, setBlobUrl] = useState<string | null>(null);

  // Swipe State
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  // Check if current song is liked
  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  // Extract Dominant Color
  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);

        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#2a2a2a'); 
      }
    };

    img.onerror = () => setDominantColor('#2a2a2a');

  }, [currentSong]);

  // Handle Full Song Download & Playback
  useEffect(() => {
    if (!currentSong) return;

    const abortController = new AbortController();
    const url = getAudioUrl(currentSong.downloadUrl);

    const loadAndPlayAudio = async () => {
      setIsBuffering(true);

      // Stop previous audio
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.removeAttribute('src');
      }

      try {
        const response = await fetch(url, { signal: abortController.signal });
        if (!response.ok) throw new Error('Network response was not ok');

        const blob = await response.blob();
        if (abortController.signal.aborted) return;

        const objectUrl = URL.createObjectURL(blob);
        setBlobUrl(prev => {
            if (prev) URL.revokeObjectURL(prev);
            return objectUrl;
        });

        if (audioRef.current) {
            audioRef.current.src = objectUrl;
            // Only play if global state says we should be playing
            // (It usually does when switching songs via click)
            try {
                await audioRef.current.play();
                setIsPlaying(true);
            } catch (e) {
                console.warn("Autoplay blocked or interrupted", e);
                setIsPlaying(false);
            }
        }
        setIsBuffering(false);

      } catch (error: any) {
        if (error.name !== 'AbortError') {
            console.error("Audio download failed", error);
            setIsBuffering(false);
            // Fallback to streaming if download fails? 
            // For now, strict requirement: "Full load krke hi play krna"
        }
      }
    };

    loadAndPlayAudio();

    return () => {
      abortController.abort();
    };
  }, [currentSong?.id]); // Re-run only when song ID changes

  // Handle Play/Pause Toggles on same song
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !blobUrl || isBuffering) return; 

    const toggle = async () => {
      try {
        if (isPlaying && audio.paused) {
          await audio.play();
        } else if (!isPlaying && !audio.paused) {
          audio.pause();
        }
      } catch (e) {
        console.error("Playback toggle error", e);
      }
    };
    toggle();
  }, [isPlaying, blobUrl, isBuffering]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleEnded = async () => {
    if (currentSong && queue.findIndex(s => s.id === currentSong.id) === queue.length - 1) {
       try {
         const artist = currentSong.artists?.primary?.[0]?.name || "";
         const query = `${artist} ${currentSong.language} songs`; 
         const similarSongs = await api.searchSongs(query);
         const newSongs = similarSongs.filter(s => !queue.some(q => q.id === s.id)).slice(0, 5);

         if (newSongs.length > 0) {
            setQueue([...queue, ...newSongs]);
         }
       } catch (e) {
         console.error("Auto-queue failed", e);
       } finally {
         nextSong();
       }
    } else {
      nextSong();
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
    }
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = (e: React.TouchEvent | React.MouseEvent | any) => {
      setIsDragging(false);
       if (audioRef.current) {
         audioRef.current.currentTime = progress;
       }
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Swipe Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;

    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;

    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    // Horizontal Swipe (Next/Prev)
    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Vertical Swipe (Down -> Close)
    if (diffY < -100 && Math.abs(diffY) > Math.abs(diffX)) {
        setFullScreen(false);
    }

    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";
  const featuredArtistName = currentSong.artists?.featured?.[0]?.name;

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={handleEnded}
            // Removed onWaiting/onCanPlay for internal state as we manually handle buffering for full download
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence>
        {isFullScreen && (
        <motion.div 
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed inset-0 z-[200] flex flex-col bg-[#0a0a0a] overflow-hidden"
            onTouchStart={handleTouchStart}
            onTouchEnd={handleTouchEnd}
        >
            {/* Dynamic Background */}
            <div className="absolute inset-0 z-0 overflow-hidden">
                <div 
                    className="absolute inset-0 transition-colors duration-1000 ease-in-out opacity-60"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #050505)` }}
                />
                 {/* Mesh Gradient Effect */}
                <div className="absolute -top-[50%] -left-[50%] w-[200%] h-[200%] opacity-30 animate-spin-slow mix-blend-overlay"
                     style={{ background: `conic-gradient(from 0deg, transparent, ${dominantColor}, transparent)` }}>
                </div>
                <div className="absolute inset-0 bg-black/20 backdrop-blur-[100px]"></div>
                {/* Noise Texture */}
                <div className="absolute inset-0 opacity-[0.04]" style={{backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 200 200\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.8\' numOctaves=\'3\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E")'}}></div>
            </div>

            {/* Main Content */}
            <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-4 md:px-12 md:pb-12">

                {/* Header */}
                <div className="flex items-center justify-between shrink-0 h-16">
                    <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full transition-colors active:scale-90">
                        <ChevronDown size={28} className="text-white" />
                    </button>
                    <div className="flex flex-col items-center opacity-0 md:opacity-100 transition-opacity">
                        <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">Playing From</span>
                        <span className="text-xs font-bold text-white">Artist Radio</span>
                    </div>
                    <button className="p-2 -mr-2 hover:bg-white/10 rounded-full transition-colors active:scale-90">
                        <MoreHorizontal size={24} className="text-white" />
                    </button>
                </div>

                {/* Album Art Section */}
                <div className="flex-1 flex items-center justify-center py-6 min-h-0">
                     <div className="relative w-full max-w-[350px] aspect-square group">
                        {/* Colored Glow Shadow */}
                        <div 
                            className="absolute inset-4 rounded-full blur-[40px] opacity-40 transition-colors duration-1000"
                            style={{ backgroundColor: dominantColor }}
                        ></div>
                        <img 
                            src={imageUrl} 
                            alt={currentSong.name} 
                            className="relative w-full h-full object-cover rounded-2xl shadow-2xl transition-transform duration-500 ease-out" 
                        />
                     </div>
                </div>

                {/* Track Info & Controls */}
                <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">

                    {/* Metadata */}
                    <div className="flex items-center justify-between">
                        <div className="flex flex-col overflow-hidden mr-6 flex-1">
                            <div className="h-8 md:h-10 relative overflow-hidden w-full">
                                {/* Marquee Effect for Long Titles */}
