const BASE_URL = 'https://musicapi-gray.vercel.app/api';

// Helper to safely get the high-quality image
export const getImageUrl = (images: { url: string }[]) => {
  if (!images || images.length === 0) return 'https://picsum.photos/500/500';
  // Always try to get index 2 (500x500), fallback to last available
  return images[2]?.url || images[images.length - 1]?.url;
};

// Helper to get high quality audio
export const getAudioUrl = (downloadUrls: { url: string }[]) => {
  if (!downloadUrls || downloadUrls.length === 0) return '';
  // The API usually returns [12kbps, 48kbps, 96kbps, 160kbps, 320kbps]
  // We want 320kbps (last) or 160kbps (second to last)
  const last = downloadUrls[downloadUrls.length - 1];
  const secondLast = downloadUrls[downloadUrls.length - 2];
  const thirdLast = downloadUrls[downloadUrls.length - 3];

  // Prefer the last one (highest quality), but ensure it exists
  return last?.url || secondLast?.url || thirdLast?.url || downloadUrls[0]?.url || '';
};

// Cloudinary Upload Helper
export const uploadToCloudinary = async (file: File): Promise<string> => {
  const cloudName = 'dj5hhott5'; 
  const uploadPreset = 'My smallest server';

  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', uploadPreset);
  formData.append('cloud_name', cloudName);

  try {
    const response = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!response.ok) {
      throw new Error('Image upload failed');
    }

    const data = await response.json();
    return data.secure_url;
  } catch (error) {
    console.error('Cloudinary upload error:', error);
    throw error;
  }
};

async function fetchJson<T>(endpoint: string): Promise<T> {
  const response = await fetch(`${BASE_URL}${endpoint}`);
  if (!response.ok) {
    throw new Error(`API Error: ${response.statusText}`);
  }
  const json = await response.json();
  return json;
}

export const api = {
  searchSongs: async (query: string): Promise<Song[]> => {
    try {
      const data = await fetchJson<{ data: { results: Song[] } }>(`/search/songs?query=${encodeURIComponent(query)}`);
      return data.data.results || [];
    } catch (e) {
      console.error("Search songs error", e);
      return [];
    }
  },

  searchAlbums: async (query: string): Promise<Album[]> => {
    try {
      const data = await fetchJson<{ data: { results: Album[] } }>(`/search/albums?query=${encodeURIComponent(query)}`);
      return data.data.results || [];
    } catch (e) {
      console.error("Search albums error", e);
      return [];
    }
  },

  searchArtists: async (query: string): Promise<Artist[]> => {
    try {
      const data = await fetchJson<{ data: { results: Artist[] } }>(`/search/artists?query=${encodeURIComponent(query)}`);
      return data.data.results || [];
    } catch (e) {
      console.error("Search artists error", e);
      return [];
    }
  },

  getAlbumDetails: async (id: string): Promise<Album | null> => {
    try {
      const data = await fetchJson<{ data: Album }>(`/albums?id=${id}`);
      return data.data || null;
    } catch (e) {
      console.error("Get album details error", e);
      return null;
    }
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist } from '../types';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,

      playSong: (song, newQueue) => {
        const { addToHistory } = get();
        addToHistory(song);
        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: true,
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => set({ isPlaying }),
      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;

        const currentIndex = queue.findIndex(s => s.id === currentSong.id);

        let nextIndex;
        if (isShuffling) {
           nextIndex = Math.floor(Math.random() * queue.length);
        } else {
           nextIndex = currentIndex + 1;
        }

        if (nextIndex < queue.length) {
          get().playSong(queue[nextIndex]);
        } else {
          set({ isPlaying: false });
        }
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        const prevIndex = currentIndex - 1;

        if (prevIndex >= 0) {
          get().playSong(queue[prevIndex]);
        }
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),

      setQueue: (songs) => set({ queue: songs }),

      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => set((state) => {
        const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
        return { history: newHistory };
      }),

      toggleLike: (song) => set((state) => {
        const isLiked = state.likedSongs.some(s => s.id === song.id);
        let newLiked;
        if (isLiked) {
          newLiked = state.likedSongs.filter(s => s.id !== song.id);
        } else {
          newLiked = [song, ...state.likedSongs];
        }
        return { likedSongs: newLiked };
      }),

      createPlaylist: (playlist) => set((state) => ({
        userPlaylists: [playlist, ...state.userPlaylists]
      })),

      addSongToPlaylist: (playlistId, song) => set((state) => ({
        userPlaylists: state.userPlaylists.map(p => {
          if (p.id === playlistId) {
             // Avoid duplicates
             if (p.songs.some(s => s.id === song.id)) return p;
             return { ...p, songs: [...p.songs, song] };
          }
          return p;
        })
      })),

      removePlaylist: (id) => set((state) => ({
        userPlaylists: state.userPlaylists.filter(p => p.id !== id)
      }))
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists
      }), 
    }
  )
);

