import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl } from '../services/api';
import { Play, Pause, Clock3, MoreHorizontal, Trash2, Music, ArrowLeft } from 'lucide-react';

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist } = usePlayerStore();

  const playlist = userPlaylists.find(p => p.id === id);

  if (!playlist) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-white">
              <h2 className="text-2xl font-bold mb-4">Playlist not found</h2>
              <button onClick={() => navigate('/library')} className="px-6 py-2 bg-white text-black rounded-full font-bold">Back to Library</button>
          </div>
      );
  }

  const handleDelete = () => {
      if (window.confirm("Are you sure you want to delete this playlist?")) {
          removePlaylist(playlist.id);
          navigate('/library');
      }
  };

  const imageUrl = getImageUrl(playlist.image);

  return (
    <div className="min-h-full pb-32 bg-gradient-to-b from-[#404040] to-black">
      {/* Sticky Header */}
      <div className="sticky top-0 z-30 px-6 py-4 flex items-center justify-between bg-transparent hover:bg-black/20 transition-colors">
          <button 
            onClick={() => navigate(-1)} 
            className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white backdrop-blur-md"
          >
             <ArrowLeft size={20} />
          </button>
          <button 
             onClick={handleDelete}
             className="w-8 h-8 rounded-full bg-black/40 hover:bg-red-500/80 flex items-center justify-center text-white backdrop-blur-md transition-colors"
             title="Delete Playlist"
          >
             <Trash2 size={16} />
          </button>
      </div>

      {/* Hero */}
      <div className="flex flex-col md:flex-row items-end gap-6 p-6 md:p-8 bg-gradient-to-b from-transparent to-black/20 -mt-16">
        <div className="w-52 h-52 shadow-2xl rounded-md bg-[#282828] flex items-center justify-center overflow-hidden shrink-0">
             {playlist.image && (playlist.image[0].url.includes('unsplash') || playlist.image[0].url.includes('cloudinary')) ? (
                 <img src={imageUrl} alt={playlist.title} className="w-full h-full object-cover" />
             ) : (
                 <Music size={80} className="text-white/20" />
             )}
        </div>
        <div className="flex flex-col gap-2 mb-2 w-full">
            <span className="uppercase text-xs font-bold tracking-wider text-white">Playlist</span>
            <h1 className="text-4xl md:text-6xl lg:text-7xl font-black tracking-tight text-white leading-none break-words line-clamp-2">{playlist.title}</h1>
            <p className="text-white/60 text-sm mt-2 line-clamp-2">{playlist.description}</p>
            <div className="flex items-center gap-2 text-sm font-bold text-white mt-2">
                <div className="w-6 h-6 rounded-full bg-gradient-to-tr from-orange-400 to-red-500 flex items-center justify-center text-[10px]">A</div>
                <span className="cursor-pointer">You</span>
                <span className="text-white/60">• {playlist.songs.length} songs</span>
            </div>
        </div>
      </div>

      {/* Actions */}
      <div className="px-6 md:px-8 py-4 bg-black/20 backdrop-blur-sm flex items-center gap-8">
         {playlist.songs.length > 0 && (
             <button 
                onClick={() => playSong(playlist.songs[0], playlist.songs)}
                className="bg-[#1DB954] hover:bg-[#1ed760] rounded-full p-4 hover:scale-105 transition-transform flex items-center justify-center shadow-lg"
             >
                 {isPlaying && playlist.songs.some(s => s.id === currentSong?.id) ? (
                     <Pause size={28} fill="black" className="text-black" />
                 ) : (
                     <Play size={28} fill="black" className="ml-1 text-black" />
                 )}
             </button>
         )}
         <button className="text-white/60 hover:text-white transition-colors">
             <MoreHorizontal size={32} />
         </button>
      </div>

      {/* List */}
      <div className="px-6 md:px-8 mt-4">
        {playlist.songs.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-white/50">
