import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User } from '../types';
import { authService } from '../services/auth';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Auth
  currentUser: User | null;

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;

  // Auth Actions
  loginUser: (user: User) => void;
  logoutUser: () => void;
  syncUserToCloud: () => void;
  updateUserProfile: (name: string, image?: string) => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,

      playSong: (song, newQueue) => {
        const { addToHistory } = get();
        addToHistory(song);
        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: true,
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => set({ isPlaying }),
      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;

        const currentIndex = queue.findIndex(s => s.id === currentSong.id);

        let nextIndex;
        if (isShuffling) {
           nextIndex = Math.floor(Math.random() * queue.length);
        } else {
           nextIndex = currentIndex + 1;
        }

        if (nextIndex < queue.length) {
          get().playSong(queue[nextIndex]);
        } else {
          set({ isPlaying: false });
        }
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        const prevIndex = currentIndex - 1;

        if (prevIndex >= 0) {
          get().playSong(queue[prevIndex]);
        }
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),

      setQueue: (songs) => set({ queue: songs }),

      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => set((state) => {
        const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
        return { history: newHistory };
      }),

      toggleLike: (song) => set((state) => {
        const isLiked = state.likedSongs.some(s => s.id === song.id);
        let newLiked;
        if (isLiked) {
          newLiked = state.likedSongs.filter(s => s.id !== song.id);
        } else {
          newLiked = [song, ...state.likedSongs];
        }
        return { likedSongs: newLiked };
      }),

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           // Sync if user logged in
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             // Fire and forget sync
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               if (p.songs.some(s => s.id === song.id)) return p;
               return { ...p, songs: [...p.songs, song] };
            }
            return p;
          });

          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
          }
          return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      loginUser: (user) => set({ 
        currentUser: user, 
        userPlaylists: user.playlists || [] // Load user playlists
      }),

      logoutUser: () => set({ 
        currentUser: null, 
        userPlaylists: [] 
      }),

      syncUserToCloud: async () => {
         const { currentUser } = get();
         if (currentUser) {
            await authService.syncUser(currentUser);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };

          authService.syncUser(updatedUser).catch(console.error);
          return { currentUser: updatedUser };
        });
      }
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser
      }), 
    }
  )
);

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { uploadToCloudinary } from '../services/api';
import { ArrowLeft, Camera, Loader2, Save, LogOut } from 'lucide-react';

export const Profile: React.FC = () => {
  const { currentUser, updateUserProfile, logoutUser } = usePlayerStore();
  const navigate = useNavigate();

  const [name, setName] = useState('');
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentUser) {
      setName(currentUser.name);
      if (currentUser.image) {
        setImagePreview(currentUser.image);
      }
    } else {
      navigate('/login');
    }
  }, [currentUser, navigate]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    try {
      let imageUrl = imagePreview;

      if (imageFile) {
        imageUrl = await uploadToCloudinary(imageFile);
      }

      updateUserProfile(name, imageUrl || undefined);
      // Optional: Show success toast
      alert('Profile updated successfully!');
    } catch (error) {
      console.error("Failed to update profile", error);
      alert('Failed to update profile.');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    if(window.confirm('Are you sure you want to log out?')) {
        logoutUser();
        navigate('/');
    }
  };

  if (!currentUser) return null;

  return (
    <div className="min-h-full bg-black text-white pb-32">
       {/* Header */}
      <div className="sticky top-0 z-30 px-6 py-4 flex items-center justify-between bg-[#121212] border-b border-white/5">
          <div className="flex items-center gap-4">
            <button 
                onClick={() => navigate(-1)} 
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-white/10 flex items-center justify-center text-white transition-colors"
            >
                <ArrowLeft size={20} />
            </button>
            <h1 className="text-xl font-bold">Edit Profile</h1>
          </div>
          <button 
             onClick={handleLogout}
             className="text-[#B3B3B3] hover:text-white flex items-center gap-2 text-sm font-bold transition-colors"
          >
             <LogOut size={16} />
             Logout
          </button>
      </div>

      <div className="max-w-2xl mx-auto p-6 md:p-10 flex flex-col gap-8">

          {/* Avatar Section */}
          <div className="flex flex-col items-center gap-4">
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="relative w-40 h-40 rounded-full bg-[#282828] group cursor-pointer overflow-hidden shadow-2xl border-4 border-[#121212]"
              >
                 {imagePreview ? (
                    <img src={imagePreview} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                    <div className="w-full h-full flex items-center justify-center text-4xl font-bold text-white/20">
                        {name.charAt(0).toUpperCase()}
                    </div>
                 )}

                 <div className="absolute inset-0 bg-black/50 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                     <Camera size={32} className="text-white mb-2" />
                     <span className="text-xs font-bold">Change Photo</span>
                 </div>
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept="image/*"
                onChange={handleImageChange}
              />
          </div>

          {/* Form */}
          <form onSubmit={handleSave} className="flex flex-col gap-6">

              <div className="flex flex-col gap-2">
                  <label className="text-sm font-bold text-[#B3B3B3]">Name</label>
                  <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="bg-[#2A2A2A] border border-transparent focus:border-white rounded-md p-3 text-white font-medium outline-none transition-all"
                    placeholder="Display Name"
                  />
              </div>

               <div className="flex flex-col gap-2">
                  <label className="text-sm font-bold text-[#B3B3B3]">Email</label>
                  <input 
                    type="text" 
                    value={currentUser.email}
                    disabled
