const CLOUD_NAME = 'dj5hhott5';
const UPLOAD_PRESET = 'My smallest server';
const GLOBAL_INDEX_ID = 'vibestream_users_index';

// Simple Hashing
export const hashPassword = async (password: string): Promise<string> => {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateUserFilename = (email: string) => {
  return `user_${email.replace(/[^a-zA-Z0-9]/g, '_')}`;
};

// Helper to save any JSON to Cloudinary
const uploadJson = async (data: any, publicId: string) => {
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const file = new File([blob], `${publicId}.json`, { type: 'application/json' });
    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', UPLOAD_PRESET);
    formData.append('cloud_name', CLOUD_NAME);
    formData.append('public_id', publicId);
    formData.append('resource_type', 'raw');
    formData.append('overwrite', 'true');

    const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/raw/upload`, {
      method: 'POST',
      body: formData,
    });
    if (!res.ok) throw new Error(`Upload failed: ${res.statusText}`);
};

// Helper to fetch any JSON
const fetchJson = async (publicId: string) => {
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/raw/upload/${publicId}.json`;
    const res = await fetch(url + `?t=${Date.now()}`);
    if (res.status === 404) return null;
    if (!res.ok) throw new Error('Fetch failed');
    return await res.json();
};

export const authService = {
  // 1. Sign Up (with Global Index update)
  signup: async (name: string, email: string, password: string): Promise<User> => {
    // Check if user exists first by trying to fetch their file
    const existing = await fetchJson(generateUserFilename(email));
    if (existing) throw new Error('User already exists.');

    const passwordHash = await hashPassword(password);

    const user: User = {
      name,
      email,
      passwordHash,
      playlists: [],
      friends: [],
      friendRequests: [],
      currentActivity: { song: null, timestamp: Date.now(), status: 'online' }
    };

    // Upload User File
    await uploadJson(user, generateUserFilename(email));

    // Update Global Index (for Search)
    // Note: In production, this is a race condition. For this demo, it's acceptable.
    try {
        let index = await fetchJson(GLOBAL_INDEX_ID) || [];
        if (!Array.isArray(index)) index = [];
        index.push({ name, email, image: '' });
        await uploadJson(index, GLOBAL_INDEX_ID);
    } catch (e) {
        console.warn("Failed to update global index", e);
    }

    return user;
  },

  // 2. Login
  login: async (email: string, password: string): Promise<User> => {
    const userData: User = await fetchJson(generateUserFilename(email));
    if (!userData) throw new Error('User not found.');

    const inputHash = await hashPassword(password);
    if (userData.passwordHash !== inputHash) throw new Error('Invalid password.');

    return userData;
  },

  // 3. Sync User (General Update)
  syncUser: async (user: User): Promise<void> => {
    await uploadJson(user, generateUserFilename(user.email));

    // Also update index image if changed
    if (user.image) {
         try {
            let index = await fetchJson(GLOBAL_INDEX_ID) || [];
            const idx = index.findIndex((u: any) => u.email === user.email);
            if (idx !== -1) {
                index[idx].image = user.image;
                index[idx].name = user.name;
                await uploadJson(index, GLOBAL_INDEX_ID);
            }
        } catch (e) { console.warn("Index update failed", e); }
    }
  },

  // 4. Search Users
  searchUsers: async (query: string): Promise<{ name: string, email: string, image?: string }[]> => {
      const index = await fetchJson(GLOBAL_INDEX_ID);
      if (!index || !Array.isArray(index)) return [];

      const lowerQ = query.toLowerCase();
      return index.filter((u: any) => u.name.toLowerCase().includes(lowerQ));
  },

  // 5. Send Friend Request
  sendFriendRequest: async (toEmail: string, fromUser: User) => {
      const targetUser: User = await fetchJson(generateUserFilename(toEmail));
      if (!targetUser) throw new Error("User not found");

      // Check if already friends or requested
      if (targetUser.friends.includes(fromUser.email)) throw new Error("Already friends");
      if (targetUser.friendRequests.some(r => r.fromEmail === fromUser.email)) throw new Error("Request already sent");

      const req: FriendRequest = {
          fromEmail: fromUser.email,
          fromName: fromUser.name,
          fromImage: fromUser.image,
          timestamp: Date.now()
      };

      targetUser.friendRequests.push(req);
      await uploadJson(targetUser, generateUserFilename(toEmail));
  },

  // 6. Accept Friend Request
  acceptFriendRequest: async (requestFromEmail: string, currentUser: User) => {
      // 1. Update Current User
      // Remove request, add to friends
      const newReqs = currentUser.friendRequests.filter(r => r.fromEmail !== requestFromEmail);
      if (!currentUser.friends.includes(requestFromEmail)) {
          currentUser.friends.push(requestFromEmail);
      }
      currentUser.friendRequests = newReqs;
      await uploadJson(currentUser, generateUserFilename(currentUser.email));

      // 2. Update the Sender User
      try {
          const sender: User = await fetchJson(generateUserFilename(requestFromEmail));
          if (sender && !sender.friends.includes(currentUser.email)) {
              sender.friends.push(currentUser.email);
              await uploadJson(sender, generateUserFilename(requestFromEmail));
          }
      } catch (e) {
          console.error("Failed to update sender friend list", e);
      }

      return currentUser;
  },

  // 7. Get Friends' Data (for Activity Feed)
  getFriendsActivity: async (friendEmails: string[]) => {
      const promises = friendEmails.map(email => fetchJson(generateUserFilename(email)));
      const users = await Promise.all(promises);
      return users.filter(u => u !== null) as User[];
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, FriendRequest } from '../types';
import { authService } from '../services/auth';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Mapped from currentUser.friends
  friendRequests: FriendRequest[];
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;

  // Auth Actions
  loginUser: (user: User) => void;
  logoutUser: () => void;
  syncUserToCloud: () => void;
  updateUserProfile: (name: string, image?: string) => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  sendFriendRequest: (toEmail: string) => Promise<void>;
  acceptFriendRequest: (fromEmail: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,

      // Social Initial State
      friends: [],
      friendRequests: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,

      playSong: (song, newQueue) => {
        const { addToHistory, partySession, currentUser } = get();
        addToHistory(song);

        // Update Cloud Status for Friends to see
        if (currentUser) {
            const updatedUser = { 
                ...currentUser, 
                currentActivity: {
                    song: song,
                    timestamp: Date.now(),
                    status: 'listening' as const
                } 
            };
            set({ currentUser: updatedUser });
            // Sync quietly
            authService.syncUser(updatedUser).catch(console.error);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: true,
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => set({ isPlaying }),
      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => set((state) => ({ history: [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20) })),

      toggleLike: (song) => set((state) => {
        const isLiked = state.likedSongs.some(s => s.id === song.id);
        return { likedSongs: isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs] };
      }),

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               if (p.songs.some(s => s.id === song.id)) return p;
               return { ...p, songs: [...p.songs, song] };
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             authService.syncUser(updatedUser).catch(console.error);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            friendRequests: user.friendRequests || []
          });
          get().refreshFriendsActivity();
      },

      logoutUser: () => set({ 
        currentUser: null, 
        userPlaylists: [],
        friends: [],
        friendRequests: [],
        partySession: null
      }),

      syncUserToCloud: async () => {
         const { currentUser } = get();
         if (currentUser) await authService.syncUser(currentUser);
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          authService.syncUser(updatedUser).catch(console.error);
          return { currentUser: updatedUser };
        });
      },

      // --- SOCIAL ACTIONS ---

      searchUsers: async (query) => {
          try {
              const results = await authService.searchUsers(query);
              // Filter out self
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) {
              console.error(e);
          }
      },

      sendFriendRequest: async (toEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          await authService.sendFriendRequest(toEmail, currentUser);
          // Optimistic UI update? No, wait for refresh.
      },

      acceptFriendRequest: async (fromEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          const updatedUser = await authService.acceptFriendRequest(fromEmail, currentUser);
          set({ currentUser: updatedUser, friendRequests: updatedUser.friendRequests });
          get().refreshFriendsActivity();
      },

      refreshFriendsActivity: async () => {
          const { currentUser } = get();
          if (!currentUser || !currentUser.friends || currentUser.friends.length === 0) {
              set({ friends: [] });
              return;
          }

          try {
              const rawFriends = await authService.getFriendsActivity(currentUser.friends);

              // Map raw User objects to the UI Friend type
              const mappedFriends: Friend[] = rawFriends.map(u => ({
                  id: u.email,
                  name: u.name,
                  image: u.image || 'https://via.placeholder.com/150',
                  status: u.currentActivity?.status || 'offline',
                  currentSong: u.currentActivity?.song || null,
                  lastActive: u.currentActivity?.timestamp || 0,
                  chatHistory: [] // Chat history would require a separate persisted file, skipping for this demo complexity
              }));

              set({ friends: mappedFriends });
          } catch (e) {
              console.error("Failed to refresh friends", e);
          }
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: (friendId, text) => set((state) => {
        const newMessage: ChatMessage = {
          id: `msg-${Date.now()}`,
          senderId: state.currentUser?.email || 'me',
          text,
          timestamp: Date.now()
        };

        const updatedFriends = state.friends.map(f => {
          if (f.id === friendId) {
             return { ...f, chatHistory: [...f.chatHistory, newMessage] };
          }
          return f;
        });

        return { friends: updatedFriends };
      }),

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        friends: state.friends // Persist friends locally
      }), 
    }
  )
);

import React, { useState, useEffect } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { ChatWindow } from '../components/ChatWindow';
import { UserPlus, MessageCircle, Music2, ChevronRight, Search, Check, X, Loader2, User } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Social: React.FC = () => {
  const { friends, friendRequests, openChat, currentUser, searchUsers, searchResults, sendFriendRequest, acceptFriendRequest, refreshFriendsActivity } = usePlayerStore();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'activity' | 'add'>('activity');
  const [query, setQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [requestStatus, setRequestStatus] = useState<{[email: string]: 'sent' | 'error' | null}>({});

  useEffect(() => {
      if (currentUser) {
          refreshFriendsActivity();
          const interval = setInterval(refreshFriendsActivity, 30000); // Poll every 30s
          return () => clearInterval(interval);
      }
  }, [currentUser]);

  const handleSearch = async (val: string) => {
      setQuery(val);
      if (val.length > 2) {
          setIsSearching(true);
          await searchUsers(val);
          setIsSearching(false);
      }
  };

  const handleSendRequest = async (email: string) => {
      setRequestStatus(prev => ({...prev, [email]: null}));
      try {
          await sendFriendRequest(email);
          setRequestStatus(prev => ({...prev, [email]: 'sent'}));
      } catch (e) {
          setRequestStatus(prev => ({...prev, [email]: 'error'}));
      }
  };

  if (!currentUser) {
      return (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center gap-4">
              <h2 className="text-xl font-bold">Connect with Friends</h2>
              <p className="text-[#B3B3B3]">Log in to see what your friends are listening to and chat with them.</p>
              <button onClick={() => navigate('/login')} className="px-8 py-3 bg-white text-black font-bold rounded-full">Log In</button>
          </div>
      );
  }

  return (
    <div className="min-h-full pb-32 bg-black px-4 pt-4">

        {/* Header Tabs */}
        <div className="flex items-center gap-4 mb-6 border-b border-[#282828] pb-2">
            <button 
                onClick={() => setActiveTab('activity')}
                className={`text-xl font-bold pb-2 border-b-2 transition-colors ${activeTab === 'activity' ? 'text-white border-[#1DB954]' : 'text-[#B3B3B3] border-transparent'}`}
            >
                Activity
            </button>
            <button 
                onClick={() => setActiveTab('add')}
                className={`text-xl font-bold pb-2 border-b-2 transition-colors ${activeTab === 'add' ? 'text-white border-[#1DB954]' : 'text-[#B3B3B3] border-transparent'}`}
            >
                Add Friends
                {friendRequests.length > 0 && <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full align-top">{friendRequests.length}</span>}
            </button>
        </div>

        {activeTab === 'activity' && (
            <div className="flex flex-col gap-2">
                {friends.length === 0 ? (
                    <div className="text-center text-[#777] mt-10">
                        <p>You haven't added any friends yet.</p>
                        <button onClick={() => setActiveTab('add')} className="text-[#1DB954] font-bold mt-2 hover:underline">Find people</button>
                    </div>
                ) : (
                    friends.map((friend) => (
                        <div 
                            key={friend.id} 
                            className="flex items-center gap-4 p-3 bg-[#121212] rounded-lg active:bg-[#1A1A1A] transition-colors cursor-pointer"
                            onClick={() => openChat(friend.id)}
                        >
                            <div className="relative">
                                <img src={friend.image || 'https://via.placeholder.com/150'} alt={friend.name} className="w-12 h-12 rounded-full object-cover" />
                                {friend.status === 'listening' && (
                                    <div className="absolute -bottom-1 -right-1 bg-[#1DB954] p-1 rounded-full border-2 border-[#121212]">
                                        <Music2 size={10} className="text-black" />
                                    </div>
                                )}
                            </div>

                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between items-center mb-1">
                                    <span className="font-bold text-white text-base truncate">{friend.name}</span>
                                    <span className="text-[10px] text-[#555]">{friend.status === 'listening' ? 'Now' : 'Offline'}</span>
                                </div>

                                {friend.status === 'listening' && friend.currentSong ? (
                                    <div className="text-[#1DB954] text-xs truncate flex items-center gap-1">
                                        <Music2 size={12} />
                                        {friend.currentSong.name}
                                    </div>
                                ) : (
                                    <div className="text-[#B3B3B3] text-xs">Tap to chat</div>
                                )}
                            </div>

                            <ChevronRight size={16} className="text-[#333]" />
                        </div>
                    ))
                )}
            </div>
        )}

        {activeTab === 'add' && (
            <div className="flex flex-col gap-6">

                {/* Friend Requests */}
                {friendRequests.length > 0 && (
                    <div className="bg-[#181818] rounded-xl p-4">
                        <h3 className="text-white font-bold mb-3">Friend Requests</h3>
                        <div className="flex flex-col gap-3">
                            {friendRequests.map((req, i) => (
                                <div key={i} className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        {req.fromImage ? (
                                            <img src={req.fromImage} className="w-10 h-10 rounded-full object-cover" alt="" />
                                        ) : (
                                            <div className="w-10 h-10 bg-[#333] rounded-full flex items-center justify-center"><User size={20}/></div>
                                        )}
                                        <div className="flex flex-col">
                                            <span className="font-bold text-sm">{req.fromName}</span>
                                            <span className="text-xs text-[#777]">wants to be friends</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => acceptFriendRequest(req.fromEmail)} className="p-2 bg-[#1DB954] rounded-full text-black hover:scale-105"><Check size={18}/></button>
                                        <button className="p-2 bg-[#333] rounded-full text-white hover:bg-[#444]"><X size={18}/></button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Search */}
                <div>
                     <h3 className="text-white font-bold mb-3">Find Friends</h3>
                     <div className="relative mb-4">
                        <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#777]" />
                        <input 
                            type="text" 
                            value={query}
                            onChange={(e) => handleSearch(e.target.value)}
                            placeholder="Search by name..."
                            className="w-full bg-[#1A1A1A] rounded-md py-3 pl-10 pr-4 text-white focus:outline-none focus:ring-1 focus:ring-[#333]"
                        />
                        {isSearching && <Loader2 size={16} className="animate-spin absolute right-3 top-1/2 -translate-y-1/2 text-[#777]" />}
                    </div>

                    <div className="flex flex-col gap-2">
                        {searchResults.map((user) => {
                            const isFriend = friends.some(f => f.id === user.email);
                            const status = requestStatus[user.email];

                            return (
                                <div key={user.email} className="flex items-center justify-between p-3 hover:bg-[#121212] rounded-lg transition-colors">
                                    <div className="flex items-center gap-3">
                                        {user.image ? (
                                            <img src={user.image} className="w-10 h-10 rounded-full object-cover" alt="" />
                                        ) : (
                                            <div className="w-10 h-10 bg-[#333] rounded-full flex items-center justify-center"><User size={20}/></div>
                                        )}
                                        <div className="flex flex-col">
                                            <span className="font-bold text-sm">{user.name}</span>
                                        </div>
                                    </div>

                                    {isFriend ? (
                                        <span className="text-xs text-[#777] font-medium">Friends</span>
                                    ) : status === 'sent' ? (
                                        <span className="text-xs text-[#1DB954] font-medium">Request Sent</span>
                                    ) : (
                                        <button 
                                            onClick={() => handleSendRequest(user.email)}
                                            className="px-3 py-1.5 bg-white text-black text-xs font-bold rounded-full hover:scale-105 transition-transform flex items-center gap-1"
                                        >
                                            <UserPlus size={14} /> Add
                                        </button>
                                    )}
                                </div>
                            );
                        })}
                        {query && searchResults.length === 0 && !isSearching && (
                            <div className="text-center text-[#555] text-sm py-4">No users found.</div>
                        )}
                    </div>
                </div>
            </div>
        )}

        <div className="md:hidden">
             <ChatWindow />
        </div>
    </div>
  );
};

import { User, FriendRequest, Song } from '../types';

const CLOUD_NAME = 'dj5hhott5';
const UPLOAD_PRESET = 'My smallest server';
const GLOBAL_INDEX_ID = 'vibestream_users_index';

// Simple Hashing
export const hashPassword = async (password: string): Promise<string> => {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateUserFilename = (email: string) => {
  return `user_${email.replace(/[^a-zA-Z0-9]/g, '_')}`;
};

// Helper to save any JSON to Cloudinary
const uploadJson = async (data: any, publicId: string) => {
    // For raw files, explicitly include the extension in the public_id
    const fullPublicId = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const file = new File([blob], fullPublicId, { type: 'application/json' });

    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', UPLOAD_PRESET);
    formData.append('public_id', fullPublicId);

    // Removing 'overwrite' and 'resource_type' from body to reduce Bad Request risk on unsigned presets

    const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/raw/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!res.ok) {
        const errBody = await res.json().catch(() => ({}));
        console.error("Cloudinary Error:", errBody);
        throw new Error(`Upload failed: ${errBody.error?.message || res.statusText}`);
    }
};

// Helper to fetch any JSON
const fetchJson = async (publicId: string) => {
    // Ensure we fetch the .json version
    const resourceName = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/raw/upload/${resourceName}`;

    const res = await fetch(url + `?t=${Date.now()}`); // Bust cache
    if (res.status === 404) return null;
    if (!res.ok) throw new Error('Fetch failed');
    return await res.json();
};

export const authService = {
  // 1. Sign Up (with Global Index update)
  signup: async (name: string, email: string, password: string): Promise<User> => {
    // Check if user exists first by trying to fetch their file
    const existing = await fetchJson(generateUserFilename(email));
    if (existing) throw new Error('User already exists.');

    const passwordHash = await hashPassword(password);

    const user: User = {
      name,
      email,
      passwordHash,
      playlists: [],
      friends: [],
      friendRequests: [],
      currentActivity: { song: null, timestamp: Date.now(), status: 'online' }
    };

    // Upload User File
    await uploadJson(user, generateUserFilename(email));

    // Update Global Index (for Search)
    // Note: In production, this is a race condition. For this demo, it's acceptable.
    try {
        let index = await fetchJson(GLOBAL_INDEX_ID) || [];
        if (!Array.isArray(index)) index = [];
        index.push({ name, email, image: '' });
        await uploadJson(index, GLOBAL_INDEX_ID);
    } catch (e) {
        console.warn("Failed to update global index", e);
    }

    return user;
  },

  // 2. Login
  login: async (email: string, password: string): Promise<User> => {
    const userData: User = await fetchJson(generateUserFilename(email));
    if (!userData) throw new Error('User not found.');

    const inputHash = await hashPassword(password);
    if (userData.passwordHash !== inputHash) throw new Error('Invalid password.');

    return userData;
  },

  // 3. Sync User (General Update)
  syncUser: async (user: User): Promise<void> => {
    await uploadJson(user, generateUserFilename(user.email));

    // Also update index image if changed
    if (user.image) {
         try {
            let index = await fetchJson(GLOBAL_INDEX_ID) || [];
            const idx = index.findIndex((u: any) => u.email === user.email);
            if (idx !== -1) {
                index[idx].image = user.image;
                index[idx].name = user.name;
                await uploadJson(index, GLOBAL_INDEX_ID);
            }
        } catch (e) { console.warn("Index update failed", e); }
    }
  },

  // 4. Search Users
  searchUsers: async (query: string): Promise<{ name: string, email: string, image?: string }[]> => {
      const index = await fetchJson(GLOBAL_INDEX_ID);
      if (!index || !Array.isArray(index)) return [];

      const lowerQ = query.toLowerCase();
      return index.filter((u: any) => u.name.toLowerCase().includes(lowerQ));
  },

  // 5. Send Friend Request
  sendFriendRequest: async (toEmail: string, fromUser: User) => {
      const targetUser: User = await fetchJson(generateUserFilename(toEmail));
      if (!targetUser) throw new Error("User not found");

      // Check if already friends or requested
      if (targetUser.friends.includes(fromUser.email)) throw new Error("Already friends");
      if (targetUser.friendRequests.some(r => r.fromEmail === fromUser.email)) throw new Error("Request already sent");

      const req: FriendRequest = {
          fromEmail: fromUser.email,
          fromName: fromUser.name,
          fromImage: fromUser.image,
          timestamp: Date.now()
      };

      targetUser.friendRequests.push(req);
      await uploadJson(targetUser, generateUserFilename(toEmail));
  },

  // 6. Accept Friend Request
  acceptFriendRequest: async (requestFromEmail: string, currentUser: User) => {
      // 1. Update Current User
      // Remove request, add to friends
      const newReqs = currentUser.friendRequests.filter(r => r.fromEmail !== requestFromEmail);
      if (!currentUser.friends.includes(requestFromEmail)) {
          currentUser.friends.push(requestFromEmail);
      }
      currentUser.friendRequests = newReqs;
      await uploadJson(currentUser, generateUserFilename(currentUser.email));

      // 2. Update the Sender User
      try {
          const sender: User = await fetchJson(generateUserFilename(requestFromEmail));
          if (sender && !sender.friends.includes(currentUser.email)) {
              sender.friends.push(currentUser.email);
              await uploadJson(sender, generateUserFilename(requestFromEmail));
          }
      } catch (e) {
          console.error("Failed to update sender friend list", e);
      }

      return currentUser;
  },

  // 7. Get Friends' Data (for Activity Feed)
  getFriendsActivity: async (friendEmails: string[]) => {
      const promises = friendEmails.map(email => fetchJson(generateUserFilename(email)));
      const users = await Promise.all(promises);
      return users.filter(u => u !== null) as User[];
  }
};

import { User, FriendRequest, Song } from '../types';

const CLOUD_NAME = 'dj5hhott5';
const UPLOAD_PRESET = 'My smallest server';
const GLOBAL_INDEX_ID = 'vibestream_users_index';

// Simple Hashing
export const hashPassword = async (password: string): Promise<string> => {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateUserFilename = (email: string) => {
  return `user_${email.replace(/[^a-zA-Z0-9]/g, '_')}`;
};

// Helper to save any JSON to Cloudinary
const uploadJson = async (data: any, publicId: string) => {
    // For raw files, explicitly include the extension in the public_id
    const fullPublicId = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const file = new File([blob], fullPublicId, { type: 'application/json' });

    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', UPLOAD_PRESET);
    formData.append('public_id', fullPublicId);

    // Attempt upload
    const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/raw/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!res.ok) {
        const errBody = await res.json().catch(() => ({}));
        console.error("Cloudinary Upload Error:", errBody);
        throw new Error(`Upload failed: ${errBody.error?.message || res.statusText}`);
    }

    return await res.json();
};

// Helper to fetch any JSON
const fetchJson = async (publicId: string) => {
    // Ensure we fetch the .json version
    const resourceName = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/raw/upload/${resourceName}`;

    // Add cache buster to ensure we get the latest data
    const res = await fetch(url + `?t=${Date.now()}`); 
    if (res.status === 404) return null;
    if (!res.ok) throw new Error('Fetch failed');
    return await res.json();
};

export const authService = {
  // 1. Sign Up (with Global Index update)
  signup: async (name: string, email: string, password: string): Promise<User> => {
    // Check if user exists
    const existing = await fetchJson(generateUserFilename(email));
    if (existing) throw new Error('User already exists.');

    const passwordHash = await hashPassword(password);

    const user: User = {
      name,
      email,
      passwordHash,
      playlists: [],
      friends: [],
      friendRequests: [],
      currentActivity: { song: null, timestamp: Date.now(), status: 'online' }
    };

    // Upload User File
    await uploadJson(user, generateUserFilename(email));

    // Update Global Index (Robustly)
    try {
        let index = [];
        try {
            const fetched = await fetchJson(GLOBAL_INDEX_ID);
            if (Array.isArray(fetched)) index = fetched;
        } catch (e) { console.warn("Index fetch failed, starting fresh."); }

        // Remove any stale entry for this email if it somehow exists
        index = index.filter((u: any) => u.email !== email);

        // Add new user
        index.push({ name, email, image: '' });

        await uploadJson(index, GLOBAL_INDEX_ID);
