        if (idx !== -1) {
            // Update existing
            index[idx].name = user.name;
            index[idx].image = user.image || '';
        } else {
            // Self-repair: Add user if missing from index
            index.push({ name: user.name, email: user.email, image: user.image || '' });
        }

        await uploadJson(index, GLOBAL_INDEX_ID);
    } catch (e) { console.warn("Index sync failed", e); }
  },

  // 4. Search Users
  searchUsers: async (query: string): Promise<{ name: string, email: string, image?: string }[]> => {
