import { User, FriendRequest, Song, UserPlaylist, ChatMessage } from '../types';

const CLOUD_NAME = 'dj5hhott5';
const UPLOAD_PRESET = 'My smallest server';

// The "Mega File" that holds all users, friends, and chats
const GLOBAL_USERS_FILE = 'vibestream_users'; 

// Simple Hashing
export const hashPassword = async (password: string): Promise<string> => {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateDataFilename = (email: string) => {
  // Sanitize email to be a valid filename
  return `data_${email.replace(/[^a-zA-Z0-9]/g, '_')}`;
};

// --- API HELPERS ---

const uploadJson = async (data: any, publicId: string) => {
    const fullPublicId = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const file = new File([blob], fullPublicId, { type: 'application/json' });

    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', UPLOAD_PRESET);
    formData.append('public_id', fullPublicId);

    const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/raw/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!res.ok) {
        throw new Error(`Upload failed: ${res.statusText}`);
    }
    return await res.json();
};

const fetchJson = async (publicId: string) => {
    const resourceName = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/raw/upload/${resourceName}`;

    // Cache bust with timestamp
    const res = await fetch(url + `?t=${Date.now()}`); 
    // Handle 404 (File not found) gracefully
    if (res.status === 404) return null;
    if (!res.ok) throw new Error('Fetch failed');
    return await res.json();
};

// --- MAIN SERVICE ---

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    // A. Fetch Global User List
    let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
    // Automatic banado: If missing, start empty array
    if (!Array.isArray(globalUsers)) globalUsers = [];

    // B. Check duplicates
    if (globalUsers.find((u: any) => u.email === email)) {
        throw new Error('User already exists.');
    }

    const passwordHash = await hashPassword(password);

    // C. Create Public Profile Object (Stored in vibestream_users.json)
    const newUserProfile = {
        name,
        email,
        passwordHash,
        image: '',
        friends: [],
        friendRequests: [],
        chats: {} // Store chats as map: friendEmail -> Message[]
    };

    // D. Create Private Data Object (Stored in data_{email}.json)
    const newUserData = {
        playlists: [],
        likedSongs: [],
        history: [],
        settings: { volume: 1 }
    };

    // E. Save Everything
    globalUsers.push(newUserProfile);

    await Promise.all([
        uploadJson(globalUsers, GLOBAL_USERS_FILE),
        uploadJson(newUserData, generateDataFilename(email))
    ]);

    // F. Return merged User object for the app state
    return {
        ...newUserProfile,
        playlists: newUserData.playlists,
        likedSongs: newUserData.likedSongs, 
        history: newUserData.history
    } as any;
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User & { chats?: any }> => {
    // A. Fetch Global Users
    const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
    if (!Array.isArray(globalUsers)) throw new Error('User database empty.');

    // B. Find User
    const userProfile = globalUsers.find((u: any) => u.email === email);
    if (!userProfile) throw new Error('User not found.');

    // C. Verify Password
    const inputHash = await hashPassword(password);
    if (userProfile.passwordHash !== inputHash) throw new Error('Invalid password.');

    // D. Fetch Private Data
    let userData = await fetchJson(generateDataFilename(email));
    if (!userData) {
        // Fallback/Auto-fix if data file is missing
        userData = { playlists: [], likedSongs: [], history: [] };
    }

    // E. Return Merged Object
    return {
        ...userProfile,
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        // Include chats so store can hydrate
        chats: userProfile.chats || {}
    } as any;
  },

  // 3. SYNC PUBLIC PROFILE (Friends, Name, Image, Chats)
  syncPublicProfile: async (user: User, chats?: Record<string, ChatMessage[]>) => {
    let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
    if (!Array.isArray(globalUsers)) globalUsers = [];

    const idx = globalUsers.findIndex((u: any) => u.email === user.email);
    if (idx !== -1) {
        // Only update public fields
        globalUsers[idx].name = user.name;
        globalUsers[idx].image = user.image;
        globalUsers[idx].friends = user.friends;
        globalUsers[idx].friendRequests = user.friendRequests;
        if (chats) {
            globalUsers[idx].chats = chats;
        }
    } else {
        // Self-repair: add if missing
        globalUsers.push({
            name: user.name,
            email: user.email,
            passwordHash: user.passwordHash,
            image: user.image,
            friends: user.friends,
            friendRequests: user.friendRequests,
            chats: chats || {}
        });
    }

    await uploadJson(globalUsers, GLOBAL_USERS_FILE);
  },

  // 4. SYNC PRIVATE DATA (Playlists, Liked Songs)
  syncPrivateData: async (user: User, additionalData: any) => {
     const dataPayload = {
         playlists: user.playlists,
         likedSongs: additionalData.likedSongs,
         history: additionalData.history
     };
     await uploadJson(dataPayload, generateDataFilename(user.email));
  },

  // 5. SEARCH USERS
  searchUsers: async (query: string) => {
      const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return [];

      const lowerQ = query.toLowerCase();
      return globalUsers.filter((u: any) => u.name.toLowerCase().includes(lowerQ)).map((u: any) => ({
          name: u.name,
          email: u.email,
          image: u.image
      }));
  },

  // 6. SEND REQUEST
  sendFriendRequest: async (toEmail: string, fromUser: User) => {
      let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return;

      const targetIdx = globalUsers.findIndex((u: any) => u.email === toEmail);
      if (targetIdx === -1) throw new Error("User not found");

      const targetUser = globalUsers[targetIdx];

      if (targetUser.friends.includes(fromUser.email)) throw new Error("Already friends");
      if (targetUser.friendRequests.some((r: any) => r.fromEmail === fromUser.email)) throw new Error("Request already sent");

      targetUser.friendRequests.push({
          fromEmail: fromUser.email,
          fromName: fromUser.name,
          fromImage: fromUser.image,
          timestamp: Date.now()
      });

      globalUsers[targetIdx] = targetUser;
      await uploadJson(globalUsers, GLOBAL_USERS_FILE);
  },

  // 7. ACCEPT REQUEST
  acceptFriendRequest: async (requestFromEmail: string, currentUser: User) => {
      let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return currentUser;

      // Update Current User in Global DB
      const myIdx = globalUsers.findIndex((u: any) => u.email === currentUser.email);
      if (myIdx !== -1) {
          const me = globalUsers[myIdx];
          me.friendRequests = me.friendRequests.filter((r: any) => r.fromEmail !== requestFromEmail);
          if (!me.friends.includes(requestFromEmail)) me.friends.push(requestFromEmail);
          globalUsers[myIdx] = me;
      }

      // Update Sender in Global DB
      const senderIdx = globalUsers.findIndex((u: any) => u.email === requestFromEmail);
      if (senderIdx !== -1) {
          const sender = globalUsers[senderIdx];
          if (!sender.friends.includes(currentUser.email)) sender.friends.push(currentUser.email);
          globalUsers[senderIdx] = sender;
      }

      await uploadJson(globalUsers, GLOBAL_USERS_FILE);

      // Return updated local user object
      const updatedUser = { ...currentUser };
      updatedUser.friendRequests = updatedUser.friendRequests.filter(r => r.fromEmail !== requestFromEmail);
      if (!updatedUser.friends.includes(requestFromEmail)) updatedUser.friends.push(requestFromEmail);

      return updatedUser;
  },

  // 8. GET FRIENDS STATUS (Includes fetching their chats if needed, though we sync ours)
  getFriendsActivity: async (friendEmails: string[]) => {
      const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return [];

      // Filter the big list for my friends
      return globalUsers.filter((u: any) => friendEmails.includes(u.email));
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, FriendRequest } from '../types';
import { authService } from '../services/auth';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Mapped from currentUser.friends
  friendRequests: FriendRequest[];
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  sendFriendRequest: (toEmail: string) => Promise<void>;
  acceptFriendRequest: (fromEmail: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,

      // Social Initial State
      friends: [],
      friendRequests: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        // Update Cloud Status (This is ephemeral, so we handle it lightly or skip for now to save bandwidth)
        // If we want real-time status in the global file, we would sync here.

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: true,
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => set({ isPlaying }),
      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            // Trigger private sync
            setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];

            // Trigger private sync
            setTimeout(() => get().syncUserToCloud('private'), 1000);

            return { likedSongs: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             // Trigger private sync
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               if (p.songs.some(s => s.id === song.id)) return p;
               return { ...p, songs: [...p.songs, song] };
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            friendRequests: user.friendRequests || []
          });

          // Hydrate friends with chats if available
          get().refreshFriendsActivity().then(() => {
              if (user.chats) {
                 set((state) => {
                     const friendsWithChats = state.friends.map(f => ({
                         ...f,
                         chatHistory: user.chats[f.id] || []
                     }));
                     return { friends: friendsWithChats };
                 });
              }
          });
      },

      logoutUser: () => set({ 
        currentUser: null, 
        userPlaylists: [],
        friends: [],
        friendRequests: [],
        partySession: null,
        likedSongs: [],
        history: []
      }),

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history, friends } = get();
         if (!currentUser) return;

         // Ensure the currentUser object has the latest playlists
         const updatedUser = { ...currentUser, playlists: userPlaylists };

         try {
             if (type === 'public' || type === 'both') {
                // Collect chats to save
                const chats: Record<string, ChatMessage[]> = {};
                friends.forEach(f => {
                    if (f.chatHistory && f.chatHistory.length > 0) {
                        chats[f.id] = f.chatHistory;
                    }
                });

                await authService.syncPublicProfile(updatedUser, chats);
             }

             if (type === 'private' || type === 'both') {
                 // We pass the loose data explicitly
                 await authService.syncPrivateData(updatedUser, { likedSongs, history });
             }
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };

          // Profile updates are public
          setTimeout(() => {
              // We need to manually call the service here because get().syncUserToCloud reads from state,
              // and state updates might be batched.
              // Note: We don't have access to latest chats here easily without full sync, 
              // so we trigger full syncPublic for simplicity
              get().syncUserToCloud('public');
          }, 100);

          return { currentUser: updatedUser };
        });
      },

      // --- SOCIAL ACTIONS ---

      searchUsers: async (query) => {
          try {
              const results = await authService.searchUsers(query);
              // Filter out self
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) {
              console.error(e);
          }
      },

      sendFriendRequest: async (toEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          await authService.sendFriendRequest(toEmail, currentUser);
      },

      acceptFriendRequest: async (fromEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          const updatedUser = await authService.acceptFriendRequest(fromEmail, currentUser);
          set({ currentUser: updatedUser, friendRequests: updatedUser.friendRequests });
          get().refreshFriendsActivity();
      },

      refreshFriendsActivity: async () => {
          const { currentUser, friends } = get();
          if (!currentUser || !currentUser.friends || currentUser.friends.length === 0) {
              set({ friends: [] });
              return;
          }

          try {
              const rawFriends = await authService.getFriendsActivity(currentUser.friends);

              // Map raw User objects to the UI Friend type
              const mappedFriends: Friend[] = rawFriends.map(u => {
                  // Preserve existing chats if we already have this friend loaded
                  const existing = friends.find(f => f.id === u.email);

                  return {
                      id: u.email,
                      name: u.name,
                      image: u.image || 'https://via.placeholder.com/150',
                      status: u.currentActivity?.status || 'offline',
                      currentSong: u.currentActivity?.song || null,
                      lastActive: u.currentActivity?.timestamp || 0,
                      chatHistory: existing ? existing.chatHistory : [] 
                  };
              });

              set({ friends: mappedFriends });
          } catch (e) {
              console.error("Failed to refresh friends", e);
          }
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: (friendId, text) => set((state) => {
        const newMessage: ChatMessage = {
          id: `msg-${Date.now()}`,
          senderId: state.currentUser?.email || 'me',
          text,
          timestamp: Date.now()
        };

        const updatedFriends = state.friends.map(f => {
          if (f.id === friendId) {
             return { ...f, chatHistory: [...f.chatHistory, newMessage] };
          }
          return f;
        });

        // Trigger sync to save chat
        setTimeout(() => get().syncUserToCloud('public'), 1000);

        return { friends: updatedFriends };
      }),

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        friends: state.friends // Persist friends locally
      }), 
    }
  )
);

import { User, FriendRequest, Song, UserPlaylist, ChatMessage } from '../types';

const CLOUD_NAME = 'dj5hhott5';
const UPLOAD_PRESET = 'My smallest server';

// The "Mega File" that holds all users, friends, and chats
const GLOBAL_USERS_FILE = 'vibestream_users'; 

// Simple Hashing
export const hashPassword = async (password: string): Promise<string> => {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateDataFilename = (email: string) => {
  // Sanitize email to be a valid filename
  return `data_${email.replace(/[^a-zA-Z0-9]/g, '_')}`;
};

// --- API HELPERS ---

const uploadJson = async (data: any, publicId: string) => {
    const fullPublicId = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const file = new File([blob], fullPublicId, { type: 'application/json' });

    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', UPLOAD_PRESET);
    formData.append('public_id', fullPublicId);

    const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/raw/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!res.ok) {
        throw new Error(`Upload failed: ${res.statusText}`);
    }
    return await res.json();
};

const fetchJson = async (publicId: string) => {
    const resourceName = publicId.endsWith('.json') ? publicId : `${publicId}.json`;
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/raw/upload/${resourceName}`;

    // STRICT Cache busting:
    // 1. Timestamp query param
    // 2. Cache-Control headers to prevent browser/CDN caching
    try {
        const res = await fetch(url + `?t=${Date.now()}&v=${Math.random()}`, {
            cache: 'no-store',
            headers: {
                'Pragma': 'no-cache',
                'Cache-Control': 'no-cache, no-store, must-revalidate'
            }
        });

        // Handle 404 (File not found) gracefully
        if (res.status === 404) return null;
        if (!res.ok) throw new Error('Fetch failed');
        return await res.json();
    } catch (e) {
        // If network error, mostly likely file doesn't exist yet or connection issue
        console.warn("Fetch warning:", e);
        return null;
    }
};

// --- MAIN SERVICE ---

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    // A. Fetch Global User List with retry logic to ensure we get the absolute latest
    let globalUsers = await fetchJson(GLOBAL_USERS_FILE);

    // Automatic banado: If missing, start empty array
    if (!Array.isArray(globalUsers)) globalUsers = [];

    // B. Check duplicates
    if (globalUsers.find((u: any) => u.email === email)) {
        throw new Error('User already exists.');
    }

    const passwordHash = await hashPassword(password);

    // C. Create Public Profile Object (Stored in vibestream_users.json)
    const newUserProfile = {
        name,
        email,
        passwordHash,
        image: '',
        friends: [],
        friendRequests: [],
        chats: {} // Store chats as map: friendEmail -> Message[]
    };

    // D. Create Private Data Object (Stored in data_{email}.json)
    const newUserData = {
        playlists: [],
        likedSongs: [],
        history: [],
        settings: { volume: 1 }
    };

    // E. Save Everything - Add to list
    globalUsers.push(newUserProfile);

    await Promise.all([
        uploadJson(globalUsers, GLOBAL_USERS_FILE),
        uploadJson(newUserData, generateDataFilename(email))
    ]);

    // F. Return merged User object for the app state
    return {
        ...newUserProfile,
        playlists: newUserData.playlists,
        likedSongs: newUserData.likedSongs, 
        history: newUserData.history
    } as any;
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User & { chats?: any }> => {
    // A. Fetch Global Users
    const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
    if (!Array.isArray(globalUsers)) throw new Error('User database empty. Please sign up first.');

    // B. Find User
    const userProfile = globalUsers.find((u: any) => u.email === email);
    if (!userProfile) throw new Error('User not found.');

    // C. Verify Password
    const inputHash = await hashPassword(password);
    if (userProfile.passwordHash !== inputHash) throw new Error('Invalid password.');

    // D. Fetch Private Data
    let userData = await fetchJson(generateDataFilename(email));
    if (!userData) {
        // Fallback/Auto-fix if data file is missing
        userData = { playlists: [], likedSongs: [], history: [] };
    }

    // E. Return Merged Object
    return {
        ...userProfile,
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        // Include chats so store can hydrate
        chats: userProfile.chats || {}
    } as any;
  },

  // 3. SYNC PUBLIC PROFILE (Friends, Name, Image, Chats)
  syncPublicProfile: async (user: User, chats?: Record<string, ChatMessage[]>) => {
    let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
    if (!Array.isArray(globalUsers)) globalUsers = [];

    const idx = globalUsers.findIndex((u: any) => u.email === user.email);
    if (idx !== -1) {
        // Only update public fields
        globalUsers[idx].name = user.name;
        globalUsers[idx].image = user.image;
        globalUsers[idx].friends = user.friends;
        globalUsers[idx].friendRequests = user.friendRequests;
        if (chats) {
            globalUsers[idx].chats = chats;
        }
    } else {
        // Self-repair: add if missing
        globalUsers.push({
            name: user.name,
            email: user.email,
            passwordHash: user.passwordHash,
            image: user.image,
            friends: user.friends,
            friendRequests: user.friendRequests,
            chats: chats || {}
        });
    }

    await uploadJson(globalUsers, GLOBAL_USERS_FILE);
  },

  // 4. SYNC PRIVATE DATA (Playlists, Liked Songs)
  syncPrivateData: async (user: User, additionalData: any) => {
     const dataPayload = {
         playlists: user.playlists,
         likedSongs: additionalData.likedSongs,
         history: additionalData.history
     };
     await uploadJson(dataPayload, generateDataFilename(user.email));
  },

  // 5. SEARCH USERS
  searchUsers: async (query: string) => {
      const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return [];

      const lowerQ = query.toLowerCase();
      return globalUsers.filter((u: any) => u.name.toLowerCase().includes(lowerQ)).map((u: any) => ({
          name: u.name,
          email: u.email,
          image: u.image
      }));
  },

  // 6. SEND REQUEST
  sendFriendRequest: async (toEmail: string, fromUser: User) => {
      let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return;

      const targetIdx = globalUsers.findIndex((u: any) => u.email === toEmail);
      if (targetIdx === -1) throw new Error("User not found");

      const targetUser = globalUsers[targetIdx];

      if (targetUser.friends.includes(fromUser.email)) throw new Error("Already friends");
      if (targetUser.friendRequests.some((r: any) => r.fromEmail === fromUser.email)) throw new Error("Request already sent");

      targetUser.friendRequests.push({
          fromEmail: fromUser.email,
          fromName: fromUser.name,
          fromImage: fromUser.image,
          timestamp: Date.now()
      });

      globalUsers[targetIdx] = targetUser;
      await uploadJson(globalUsers, GLOBAL_USERS_FILE);
  },

  // 7. ACCEPT REQUEST
  acceptFriendRequest: async (requestFromEmail: string, currentUser: User) => {
      let globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return currentUser;

      // Update Current User in Global DB
      const myIdx = globalUsers.findIndex((u: any) => u.email === currentUser.email);
      if (myIdx !== -1) {
          const me = globalUsers[myIdx];
          me.friendRequests = me.friendRequests.filter((r: any) => r.fromEmail !== requestFromEmail);
          if (!me.friends.includes(requestFromEmail)) me.friends.push(requestFromEmail);
          globalUsers[myIdx] = me;
      }

      // Update Sender in Global DB
      const senderIdx = globalUsers.findIndex((u: any) => u.email === requestFromEmail);
      if (senderIdx !== -1) {
          const sender = globalUsers[senderIdx];
          if (!sender.friends.includes(currentUser.email)) sender.friends.push(currentUser.email);
          globalUsers[senderIdx] = sender;
      }

      await uploadJson(globalUsers, GLOBAL_USERS_FILE);

      // Return updated local user object
      const updatedUser = { ...currentUser };
      updatedUser.friendRequests = updatedUser.friendRequests.filter(r => r.fromEmail !== requestFromEmail);
      if (!updatedUser.friends.includes(requestFromEmail)) updatedUser.friends.push(requestFromEmail);

      return updatedUser;
  },

  // 8. GET FRIENDS STATUS (Includes fetching their chats if needed, though we sync ours)
  getFriendsActivity: async (friendEmails: string[]) => {
      const globalUsers = await fetchJson(GLOBAL_USERS_FILE);
      if (!Array.isArray(globalUsers)) return [];

      // Filter the big list for my friends
      return globalUsers.filter((u: any) => friendEmails.includes(u.email));
  }
};

